/** Parser for Assignment 2 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {
  
  private Lexer in;
  
  Parser(Lexer i) {
    in = i;
  }
  
  Parser(Reader inputStream) { this(new Lexer(inputStream)); }
  
  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }
  
  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) 
    * Input ::= Exp
    */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token t = in.readToken();
    if (t != null) throw new ParseException("Expected EOF, found " + t);
    return result;
  }
  
  /** Parses:
    *   Exp ::= if Exp then Exp else Exp
    *         | let Def+ in Exp
    *         | map IdList to Exp
    *         | BinaryExp
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF) {
      return parseIf();
    } else if (t == Lexer.LET) {
      return parseLet();
    } else if (t == Lexer.MAP) {
      return parseMap();
    } else {
      return parseBinaryExp();
    }
  }

  /** Parses: if Exp then Exp else Exp */
  private AST parseIf() {
    consume(Lexer.IF);
    AST test = parseExp();
    consume(Lexer.THEN);
    AST conseq = parseExp();
    consume(Lexer.ELSE);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let Def+ in Exp */
  private AST parseLet() {
    consume(Lexer.LET);
    List<Def> defs = new ArrayList<>();
    defs.add(parseDef());
    while (in.peek() instanceof Variable) {
      defs.add(parseDef());
    }
    consume(Lexer.IN);
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: Def ::= Id := Exp ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable)) throw new ParseException("Expected variable, found " + t);
    Variable lhs = (Variable)t;
    consume(Lexer.BIND);
    AST rhs = parseExp();
    consume(SemiColon.ONLY);
    return new Def(lhs, rhs);
  }

  /** Parses: map IdList to Exp */
  private AST parseMap() {
    consume(Lexer.MAP);
    Variable[] vars = parseIdList();
    consume(Lexer.TO);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: IdList ::= { PropIdList } */
  private Variable[] parseIdList() {
    if (in.peek() == Lexer.TO) return new Variable[0];
    return parsePropIdList();
  }

  /** Parses: PropIdList ::= Id { , Id }* */
  private Variable[] parsePropIdList() {
    List<Variable> vars = new ArrayList<>();
    Token t = in.readToken();
    if (!(t instanceof Variable)) throw new ParseException("Expected variable, found " + t);
    vars.add((Variable)t);
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      t = in.readToken();
      if (!(t instanceof Variable)) throw new ParseException("Expected variable, found " + t);
      vars.add((Variable)t);
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: BinaryExp ::= Term { Binop Term }* (left associatively!) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (true) {
      Token t = in.peek();
      if (t instanceof OpToken && ((OpToken)t).isBinOp()) {
        in.readToken(); // consume
        AST right = parseTerm();
        left = new BinOpApp(((OpToken)t).toBinOp(), left, right);
      } else {
        break;
      }
    }
    return left;
  }

  /** Parses:
    *   Term ::= Unop Term
    *          | Factor { ( ExpList ) }
    *          | Empty
    *          | Int
    *          | Bool
    */
  private AST parseTerm() {
    Token t = in.peek();
    if (t instanceof OpToken && ((OpToken)t).isUnOp()) {
      in.readToken();
      AST arg = parseTerm();
      return new UnOpApp(((OpToken)t).toUnOp(), arg);
    }
    if (t == EmptyConstant.ONLY) {
      in.readToken();
      return EmptyConstant.ONLY;
    }
    if (t instanceof IntConstant) {
      in.readToken();
      return (IntConstant)t;
    }
    if (t instanceof BoolConstant) {
      in.readToken();
      return (BoolConstant)t;
    }
    
    AST factor = parseFactor();
    // Peek for application: Factor { ( ExpList ) }
    if (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      consume(RightParen.ONLY);
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: Factor ::= ( Exp ) | Prim | Id */
  private AST parseFactor() {
    Token t = in.readToken();
    if (t == LeftParen.ONLY) {
      AST exp = parseExp();
      consume(RightParen.ONLY);
      return exp;
    }
    if (t instanceof PrimFun) {
      return (PrimFun)t;
    }
    if (t instanceof Variable) {
      return (Variable)t;
    }
    if (t == null) throw new ParseException("Unexpected EOF");
    throw new ParseException("Unexpected token: " + t);
  }

  /** Parses: ExpList ::= { PropExpList } */
  private AST[] parseExpList() {
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];
    }
    return parsePropExpList();
  }

  /** Parses: PropExpList ::= Exp { , Exp }* */
  private AST[] parsePropExpList() {
    List<AST> exps = new ArrayList<>();
    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      exps.add(parseExp());
    }
    return exps.toArray(new AST[0]);
  }

  /** Consumes a token if it matches the expected token, otherwise throws ParseException */
  private void consume(Token expected) {
    Token t = in.readToken();
    if (t != expected) throw new ParseException("Expected " + expected + ", found " + t);
  }

}

import junit.framework.*;
import java.io.*;

public class AgentTest extends TestCase {

  public AgentTest (String name) {
    super(name);
  }

  protected void checkString(String name, String answer, String program) {
    Parser p = new Parser(new StringReader(program));
    assertEquals(name, answer, p.parse().toString());
  }

  protected void checkError(String name, String program) {
    try {
      Parser p = new Parser(new StringReader(program));
      p.parse();
      fail(name + " should have thrown ParseException");
    } catch (ParseException e) {
      // Expected
    }
  }

  public void testBinaryAssociativity() {
    checkString("assoc", "((1 + 2) + 3)", "1 + 2 + 3");
    checkString("same precedence", "((1 + 2) * 3)", "1 + 2 * 3");
    checkString("same precedence 2", "((1 * 2) + 3)", "1 * 2 + 3");
  }

  public void testUnary() {
    checkString("unary plus", "+ 1", "+1");
    checkString("unary minus", "- 1", "-1");
    checkString("unary tilde", "~ true", "~true");
    checkString("unary nested", "+ ~ 1", "+ ~ 1");
    checkString("unary in binop", "(1 + - 2)", "1 + -2");
  }

  public void testIf() {
    checkString("if", "if true then 1 else 0", "if true then 1 else 0");
    checkString("nested if", "if true then if false then 1 else 2 else 0", "if true then if false then 1 else 2 else 0");
    checkString("if in else", "if true then 1 else (2 + 3)", "if true then 1 else 2 + 3");
  }

  public void testLet() {
    checkString("let", "let x := 1; in x", "let x := 1; in x");
    checkString("let multi", "let x := 1; y := 2; in (x + y)", "let x := 1; y := 2; in x + y");
    checkString("let recursive", "let x := let y := 1; in y; in x", "let x := let y := 1; in y; in x");
  }

  public void testMap() {
    checkString("map", "map x to x", "map x to x");
    checkString("map multi", "map x,y to (x + y)", "map x, y to x + y");
    checkString("map empty", "map  to 1", "map to 1");
  }

  public void testApp() {
    checkString("app 0", "f()", "f()");
    checkString("app 1", "f(1)", "f(1)");
    checkString("app 2", "f(1, 2)", "f(1, 2)");
    checkString("curried", "(f(1))(2)", "(f(1))(2)");
    checkString("prim app", "first(x)", "first(x)");
    checkString("paren app", "(map x to x)(1)", "(map x to x)(1)");
  }

  public void testComplex() {
    checkString("complex 1", "((x + y) * (if true then 1 else (2 - 3)))", "(x + y) * (if true then 1 else 2 - 3)");
  }

  public void testErrors() {
    checkError("missing semi", "let x := 1 in x");
    checkError("missing then", "if true 1 else 0");
    checkError("missing in", "let x := 1; x");
    checkError("unmatched paren", "(1 + 2");
    checkError("extra token", "1 + 2 3");
    checkError("illegal char", "1 @ 2");
    checkError("if as binop operand", "1 + if true then 1 else 0");
  }
}

